head.b:skin:
.navbar { display: none !important; }
#navbar-iframe { display: none !important; }
.blog-feeds { display: none !important; }

/* === Claude Bridge Dark Theme — Blue-Purple === */
:root {
  --bg-primary: #0a0a0f;
  --bg-secondary: #12121a;
  --bg-card: #16161f;
  --bg-card-hover: #1e1e2a;
  --bg-header: rgba(10, 10, 15, 0.85);
  --border: rgba(255, 255, 255, 0.06);
  --border-hover: rgba(255, 255, 255, 0.12);
  --text-primary: #e8e8ed;
  --text-secondary: #8888a0;
  --text-muted: #4a4a60;
  --accent: #7c5cfc;
  --accent-hover: #9178ff;
  --accent-glow: rgba(124, 92, 252, 0.15);
  --blue: #3b82f6;
  --green: #34d399;
  --orange: #fb923c;
  --red: #f87171;
  --purple: #a78bfa;
  --cyan: #22d3ee;
  --shadow-sm: 0 1px 4px rgba(0,0,0,0.4);
  --shadow-md: 0 4px 16px rgba(0,0,0,0.5);
  --shadow-lg: 0 12px 40px rgba(0,0,0,0.6);
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-xl: 20px;
  --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, 'SF Pro Display', sans-serif;
  --font-mono: 'SF Mono', SFMono-Regular, ui-monospace, Menlo, monospace;
  --ease-spring: cubic-bezier(0.25, 0.46, 0.45, 0.94);
  --ease-out: cubic-bezier(0, 0, 0.2, 1);
}

* { margin: 0; padding: 0; box-sizing: border-box; }
body {
  background: var(--bg-primary);
  color: var(--text-primary);
  font-family: var(--font-sans);
  font-size: 15px;
  line-height: 1.65;
  min-height: 100vh;
  -webkit-font-smoothing: antialiased;
}
a { text-decoration: none; color: var(--accent); }
a:hover { color: var(--accent-hover); }

/* === Header === */
.header {
  position: sticky; top: 0; z-index: 100;
  background: var(--bg-header);
  backdrop-filter: saturate(180%) blur(20px);
  -webkit-backdrop-filter: saturate(180%) blur(20px);
  border-bottom: 0.5px solid var(--border);
}
.header-inner {
  max-width: 980px; margin: 0 auto;
  padding: 0 max(22px, env(safe-area-inset-left));
  height: 52px;
  display: flex; align-items: center; justify-content: space-between;
}
.logo { display: flex; align-items: center; gap: 10px; }
.logo-icon { font-size: 22px; }
.logo-text {
  font-size: 17px; font-weight: 600;
  letter-spacing: -0.022em;
  color: var(--text-primary);
}
.logo-text span { color: var(--text-muted); font-weight: 400; font-size: 13px; margin-left: 6px; }
.header-nav { display: flex; gap: 20px; font-size: 13px; }
.header-nav a { color: var(--text-secondary); transition: color 0.2s; }
.header-nav a:hover { color: var(--text-primary); }

/* === Hero Section (Homepage only) === */
.hero {
  max-width: 980px; margin: 0 auto;
  padding: 80px 22px 60px;
  text-align: center;
}
.hero-badge {
  display: inline-block;
  font-size: 12px; font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--accent);
  background: var(--accent-glow);
  padding: 6px 16px;
  border-radius: 20px;
  border: 1px solid rgba(124, 92, 252, 0.2);
  margin-bottom: 24px;
}
.hero h1 {
  font-size: clamp(32px, 5vw, 52px);
  font-weight: 700;
  letter-spacing: -0.03em;
  line-height: 1.1;
  margin-bottom: 16px;
  background: linear-gradient(135deg, #e8e8ed 0%, #a78bfa 50%, #7c5cfc 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.hero-sub {
  font-size: 18px;
  color: var(--text-secondary);
  max-width: 560px;
  margin: 0 auto 32px;
  line-height: 1.6;
}
.hero-actions { display: flex; gap: 12px; justify-content: center; flex-wrap: wrap; }
.btn {
  display: inline-flex; align-items: center; gap: 8px;
  padding: 12px 28px;
  border-radius: var(--radius-md);
  font-size: 14px; font-weight: 600;
  transition: all 0.2s var(--ease-out);
  cursor: pointer; border: none;
}
.btn-primary {
  background: var(--accent);
  color: #fff;
}
.btn-primary:hover { background: var(--accent-hover); color: #fff; transform: translateY(-1px); }
.btn-secondary {
  background: var(--bg-card);
  color: var(--text-primary);
  border: 1px solid var(--border);
}
.btn-secondary:hover { border-color: var(--border-hover); color: var(--text-primary); transform: translateY(-1px); }

/* === Feature Cards === */
.features {
  max-width: 980px; margin: 0 auto;
  padding: 0 22px 60px;
  display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 16px;
}
.feature-card {
  background: var(--bg-card);
  border-radius: var(--radius-lg);
  padding: 28px;
  border: 1px solid var(--border);
  transition: all 0.3s var(--ease-out);
}
.feature-card:hover {
  border-color: var(--border-hover);
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
}
.feature-icon { font-size: 28px; margin-bottom: 16px; }
.feature-title {
  font-size: 16px; font-weight: 600;
  margin-bottom: 8px;
  color: var(--text-primary);
}
.feature-desc {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.6;
}

/* === Blog Posts Section === */
.posts-section {
  max-width: 980px; margin: 0 auto;
  padding: 0 22px 80px;
}
.section-title {
  font-size: 13px; font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--text-muted);
  margin-bottom: 20px;
  padding-bottom: 12px;
  border-bottom: 1px solid var(--border);
}
.post-card {
  background: var(--bg-card);
  border-radius: var(--radius-md);
  padding: 20px 24px;
  margin-bottom: 12px;
  border: 1px solid var(--border);
  transition: all 0.3s var(--ease-out);
  display: block;
}
.post-card:hover {
  border-color: var(--border-hover);
  transform: translateY(-1px);
  box-shadow: var(--shadow-md);
  color: var(--text-primary);
}
.post-title {
  font-size: 16px; font-weight: 600;
  margin-bottom: 6px;
  color: var(--text-primary);
}
.post-meta {
  font-size: 12px;
  color: var(--text-muted);
  margin-bottom: 8px;
}
.post-snippet {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.6;
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
.post-labels { margin-top: 10px; display: flex; gap: 6px; flex-wrap: wrap; }
.label-tag {
  font-size: 11px; font-weight: 500;
  padding: 3px 10px;
  border-radius: 12px;
  background: var(--accent-glow);
  color: var(--purple);
}

/* === Single Post View === */
.post-view {
  max-width: 720px; margin: 0 auto;
  padding: 40px 22px 80px;
}
.post-view h1.post-view-title {
  font-size: clamp(24px, 4vw, 36px);
  font-weight: 700;
  letter-spacing: -0.02em;
  line-height: 1.2;
  margin-bottom: 12px;
}
.post-view .post-view-meta {
  font-size: 13px;
  color: var(--text-muted);
  margin-bottom: 32px;
  padding-bottom: 20px;
  border-bottom: 1px solid var(--border);
}
.post-view .post-body {
  font-size: 15px;
  line-height: 1.8;
  color: var(--text-secondary);
}
.post-body h2 {
  font-size: 22px; font-weight: 600;
  color: var(--text-primary);
  margin: 32px 0 12px;
  letter-spacing: -0.01em;
}
.post-body h3 {
  font-size: 18px; font-weight: 600;
  color: var(--text-primary);
  margin: 24px 0 8px;
}
.post-body p { margin-bottom: 16px; }
.post-body ul, .post-body ol {
  margin: 12px 0 16px 20px;
  color: var(--text-secondary);
}
.post-body li { margin-bottom: 6px; }
.post-body code {
  font-family: var(--font-mono);
  font-size: 13px;
  background: var(--bg-secondary);
  padding: 2px 6px;
  border-radius: 4px;
  color: var(--purple);
}
.post-body pre {
  background: var(--bg-secondary);
  border-radius: var(--radius-sm);
  padding: 16px 20px;
  margin: 16px 0;
  overflow-x: auto;
  border: 1px solid var(--border);
}
.post-body pre code {
  background: transparent;
  padding: 0;
  color: var(--text-secondary);
}

/* === Footer === */
.footer {
  max-width: 980px; margin: 0 auto;
  padding: 24px 22px;
  border-top: 1px solid var(--border);
  text-align: center;
  font-size: 12px;
  color: var(--text-muted);
}

/* === Responsive === */
@media (max-width: 640px) {
  .hero { padding: 48px 16px 40px; }
  .features { padding: 0 16px 40px; }
  .header-nav { gap: 12px; }
  .feature-card { padding: 20px; }
}

body.script:
//
function renderBlogPosts(data){
  var container = document.getElementById('posts-container');
  if(!container) return;
  try {
    var entries = data.feed.entry;
    if(!entries || entries.length === 0){ container.innerHTML='<div style="color:var(--text-muted)">No posts yet</div>'; return; }
    var html = '';
    for(var i=0; i<entries.length; i++){
      var e = entries[i];
      var title = e.title.$t || '';
      var published = e.published.$t || '';
      var dateStr = published.substring(0,10);
      var url = '';
      for(var j=0; j<e.link.length; j++){
        if(e.link[j].rel === 'alternate'){ url = e.link[j].href; break; }
      }
      var snippet = '';
      if(e.content) snippet = e.content.$t.replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').substring(0,280).trim() + '...';
      var labels = '';
      if(e.category){
        labels = '<div class="post-labels">';
        for(var k=0; k<e.category.length; k++){
          labels += '<span class="label-tag">' + e.category[k].term + '</span>';
        }
        labels += '</div>';
      }
      html += '<a class="post-card" href="'+url+'">'
        + '<div class="post-title">'+title+'</div>'
        + '<div class="post-meta">'+dateStr+'</div>'
        + '<div class="post-snippet">'+snippet+'</div>'
        + labels + '</a>';
    }
    container.innerHTML = html;
  } catch(ex) {
    container.innerHTML='<div style="color:#f87171">Error: '+ex.message+'</div>';
  }
}
//
